def process_batch(rows):
    ok, q = [], []
    for r in rows:
        if not r.get("id"):
            q.append({"row": r, "reason": "data:missing_id"})
        else:
            ok.append(r)
    return {"ok": ok, "quarantined": q, "in": len(rows)}

rows = [{"id": 1}, {}, {"id": 2}]
r = process_batch(rows)
assert r["in"] == len(r["ok"]) + len(r["quarantined"])
print(r)

